    if (!url) return;
    try {
      Alert.alert('Downloading', 'Please wait...');
      const safeFilename = filename || 'downloaded_file';

      // Ensure the filename is unique to avoid "Destination already exists" collisions internally
      const timestamp = new Date().getTime();
      const dotIndex = safeFilename.lastIndexOf('.');
      const uniqueFilename = dotIndex !== -1 
        ? `${safeFilename.substring(0, dotIndex)}_${timestamp}${safeFilename.substring(dotIndex)}`
        : `${safeFilename}_${timestamp}`;

      const file = new FSFile(Paths.document, uniqueFilename);
      const downloadResult = await FSFile.downloadFileAsync(url, file);

      if (Platform.OS === 'android') {
        // Use StorageAccessFramework for an explicit "Save As" dialogue native to Android Downloads
        const permissions = await FileSystemLegacy.StorageAccessFramework.requestDirectoryPermissionsAsync();
        if (permissions.granted) {
          const base64 = await FileSystemLegacy.readAsStringAsync(downloadResult.uri, { encoding: FileSystemLegacy.EncodingType.Base64 });
          const newFileUri = await FileSystemLegacy.StorageAccessFramework.createFileAsync(
            permissions.directoryUri,
            uniqueFilename,
            'application/octet-stream'
          );
          await FileSystemLegacy.writeAsStringAsync(newFileUri, base64, { encoding: FileSystemLegacy.EncodingType.Base64 });
          Alert.alert('Success', 'File successfully downloaded to your device storage!');
        } else {
          Alert.alert('Error', 'Storage permission denied. File not saved.');
        }
      } else {
        // iOS fully relies on share/action sheets for saving files natively
        await Sharing.shareAsync(downloadResult.uri);
